var spots = {
	"U_CALLIDUS_ASSASSIN_A": [160, 480],
	"U_WITCHSEEKERS_A": [650, 480],
	"U_WITCHSEEKERS_B": [1140, 480],
	"U_PROSECUTORS_A": [1620, 480],
	"U_BLADE_CHAMPION_A": [160, 880],
	"U_CUSTODIAN_GUARD_A": [650, 880],
	"U_CUSTODIAN_GUARD_B": [1140, 880],
	"U_VERTUS_PRAETORS_A": [1620, 880],
	"U_BLADE_CHAMPION_B": [160, 1280],
	"U_CUSTODIAN_GUARD_C": [650, 1280],
	"U_CUSTODIAN_GUARD_D": [1140, 1280],
	"U_TRAJANN_VALORIS_A": [1620, 1280],
	"U_SHIELD-CAPTAIN_ON_DAWNEAGLE_JETBIKE_A": [160, 1680],
	"U_CUSTODIAN_GUARD_E": [650, 1680],
	"U_ALLARUS_CUSTODIANS_A": [1140, 1680],
	"U_INQUISITOR_DRAXUS_A": [1620, 1680]
}
for uid in spots:
	var u = GameState.state["units"].get(uid, null)
	if u == null:
		continue
	var cx = float(spots[uid][0])
	var cy = float(spots[uid][1])
	var alive_i = 0
	for m in u["models"]:
		if not m.get("alive", true):
			continue
		m["position"] = {"x": cx - 72.0 + float(alive_i) * 36.0, "y": cy}
		alive_i += 1
return true

var snap = GameState.create_snapshot()
var n = 0
for uid in snap["units"]:
	var u = snap["units"][uid]
	if int(u.get("owner", -1)) != 1:
		continue
	if FactionAbilityManager.check_against_all_odds(u, snap):
		n += 1
GameState.set_meta("aao_before", n)
print("SCENARIO aao_before=%d" % n)
return n

var snap = GameState.create_snapshot()
var n = 0
var lines = []
for uid in snap["units"]:
	var u = snap["units"][uid]
	if int(u.get("owner", -1)) != 1:
		continue
	var iso = FactionAbilityManager.check_against_all_odds(u, snap)
	if iso:
		n += 1
	var gap = AIDecisionMaker._aao_min_friendly_gap_inches(u, snap, 1)
	lines.append("%s gap=%.1f iso=%s" % [uid, gap, str(iso)])
print("SCENARIO aao_after=%d before=%d" % [n, int(GameState.get_meta("aao_before", 0))])
for l in lines:
	print("SCENARIO GAP " + l)
return n

var alive = 0
for uid in GameState.state["units"]:
	var u = GameState.state["units"][uid]
	if int(u.get("owner", -1)) != 1:
		continue
	for m in u.get("models", []):
		if m.get("alive", true):
			alive += 1
		break
return alive
